/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `employee_payslip_report` AS select `p`.`payroll_id` AS `Payroll ID`,`e`.`employee_id` AS `Employee ID`,concat(`e`.`last_name`,', ',`e`.`first_name`) AS `Employee Name`,`pos`.`name` AS `Position`,`d`.`department_name` AS `Department`,`pp`.`start_date` AS `Period Start`,`pp`.`end_date` AS `Period End`,`sd`.`basic_salary` AS `Monthly Base Salary`,`sd`.`hourly_rate` AS `Hourly Rate`,`p`.`total_work_hours` AS `Hours Rendered`,round((`p`.`total_work_hours` / 8),1) AS `Days Worked`,`p`.`overtime_hours` AS `OT Hours`,round((`p`.`total_work_hours` * `sd`.`hourly_rate`),2) AS `Basic Earned Pay`,round((`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25)),2) AS `Overtime Pay`,round(((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))),2) AS `Gross Income`,round((`p`.`total_benefits` / 2),2) AS `Cutoff Benefits`,round((coalesce((select `sc`.`employee_share` from `sss_contribution` `sc` where ((`sd`.`basic_salary` >= `sc`.`min_salary`) and (`sd`.`basic_salary` <= `sc`.`max_salary`)) limit 1),1125.00) / 2),2) AS `SSS Deduction`,(case when (`sd`.`basic_salary` <= 10000.00) then round((500.00 / 4),2) when (`sd`.`basic_salary` >= 100000.00) then round((5000.00 / 4),2) else round(((`sd`.`basic_salary` * 0.05) / 4),2) end) AS `PhilHealth Deduction`,100.00 AS `Pag-IBIG Deduction`,(case when (((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))) <= 10417.00) then 0.00 else round(((((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))) - 10417.00) * 0.20),2) end) AS `Withholding Tax`,round(((((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))) + (`p`.`total_benefits` / 2)) - ((((case when (((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))) <= 10417.00) then 0.00 else ((((`p`.`total_work_hours` * `sd`.`hourly_rate`) + (`p`.`overtime_hours` * (`sd`.`hourly_rate` * 1.25))) - 10417.00) * 0.20) end) + (coalesce((select `sc`.`employee_share` from `sss_contribution` `sc` where ((`sd`.`basic_salary` >= `sc`.`min_salary`) and (`sd`.`basic_salary` <= `sc`.`max_salary`)) limit 1),1125.00) / 2)) + ((case when (`sd`.`basic_salary` <= 10000.00) then 500.00 when (`sd`.`basic_salary` >= 100000.00) then 5000.00 else (`sd`.`basic_salary` * 0.05) end) / 4)) + 100.00)),2) AS `Net Take-Home Pay` from (((((`employee_profile` `e` left join `department` `d` on((`e`.`department_id` = `d`.`department_id`))) left join `position` `pos` on((`e`.`position_id` = `pos`.`position_id`))) left join `salary_details` `sd` on((`e`.`employee_id` = `sd`.`employee_id`))) left join `payroll` `p` on((`e`.`employee_id` = `p`.`employee_id`))) left join `pay_period` `pp` on((`p`.`payperiod_id` = `pp`.`payperiod_id`))) */;
